// ─── Preflight + artifact creation ────────────────────────────────────────────

/**
 * runPreflightChecks(paths)
 * Verifies the learning directory structure is accessible.
 * Returns { passed: boolean, checks: Array<{ name, ok, detail }> }
 * The session_note_exists check is non-blocking (passed ignores it).
 */
export async function runPreflightChecks(paths) {
  const today = new Date().toISOString().slice(0, 10);

  async function check(name, fn) {
    try {
      const detail = await fn();
      return { name, ok: true, detail: detail ?? '' };
    } catch (err) {
      return { name, ok: false, detail: err.message };
    }
  }

  const results = await Promise.all([
    check('mastery_notes_exist', async () => {
      const files = await readdir(paths.mastery);
      const count = files.filter(f => f.endsWith('.md')).length;
      if (count === 0) throw new Error('No mastery notes found');
      return `${count} mastery notes found`;
    }),
    check('nodes_dir_accessible', async () => {
      await readdir(paths.nodes);
      return '';
    }),
    check('connections_dir_accessible', async () => {
      await readdir(paths.connections);
      return '';
    }),
    check('session_note_exists', async () => {
      await access(join(paths.sessions, `${today}.md`));
      return `Session note exists for ${today}`;
    }),
  ]);

  // session_note_exists (index 3) is non-blocking — exclude from passed calc
  const blocking = results.slice(0, 3);
  const passed = blocking.every(c => c.ok);
  return { passed, checks: results };
}

function slugify(str) {
  return str.trim().replace(/\s+/g, '-').replace(/[^a-zA-Z0-9-]/g, '');
}

async function fileExists(path) {
  try {
    await access(path);
    return true;
  } catch {
    return false;
  }
}

async function uniqueSlugPath(dir, slug, ext = '.md') {
  let candidate = join(dir, slug + ext);
  if (!(await fileExists(candidate))) return { path: candidate, slug };
  let n = 2;
  while (await fileExists(join(dir, `${slug}-${n}${ext}`))) n++;
  const finalSlug = `${slug}-${n}`;
  return { path: join(dir, finalSlug + ext), slug: finalSlug };
}

/**
 * createNode(paths, fields)
 * Creates a new node note from the Node.md template.
 * fields: { node_name, primary_domain, definition, core_mechanism,
 *           why_it_matters, example, origin_session, confidence_rating }
 * Returns: { path, slug }
 */
export async function createNode(paths, fields) {
  const today = new Date().toISOString().slice(0, 10);
  const tomorrow = (() => {
    const d = new Date(); d.setDate(d.getDate() + 1);
    return d.toISOString().slice(0, 10);
  })();

  const templatePath = join(paths.root, '06_Templates', 'Node.md');
  let template = await readFile(templatePath, 'utf8');

  const rawSlug = slugify(fields.node_name || 'Unnamed-Node');
  const { path: filePath, slug } = await uniqueSlugPath(paths.nodes, rawSlug);

  // Replace template placeholders
  let text = template
    .replace(/\{\{date\}\}/g, today)
    .replace(/\{\{title\}\}/g, fields.node_name || slug);

  // Fill inline fields
  const inlineUpdates = {
    node_name: fields.node_name || slug,
    primary_domain: fields.primary_domain || '',
    confidence_rating: fields.confidence_rating ?? 0,
    origin_session: fields.origin_session || today,
    next_review_due: tomorrow,
    review_stage: 'new',
  };
  text = serializeMastery(text, inlineUpdates);

  // Fill YAML frontmatter fields
  text = text
    .replace(/^node_name:$/m, `node_name: ${fields.node_name || slug}`)
    .replace(/^primary_domain:$/m, `primary_domain: ${fields.primary_domain || ''}`)
    .replace(/^origin_session:$/m, `origin_session: ${fields.origin_session || today}`)
    .replace(/^confidence_rating: 0$/m, `confidence_rating: ${fields.confidence_rating ?? 0}`);

  // Fill section bodies
  if (fields.definition) {
    text = text.replace(
      /^> \*Simple, clear\. One or two sentences\.\*$/m,
      fields.definition,
    );
  }
  if (fields.core_mechanism) {
    text = text.replace(
      /^\*How does it work\? Input → process → output\.\*$/m,
      fields.core_mechanism,
    );
  }
  if (fields.why_it_matters) {
    text = text.replace(
      /^\*Why is this node useful across multiple contexts\?\*$/m,
      fields.why_it_matters,
    );
  }
  if (fields.example) {
    text = text.replace(
      /^\*One concrete, real-world instance\.\*$/m,
      fields.example,
    );
  }
  if (fields.primary_domain) {
    text = text.replace(/^- \*\*Primary:\*\*$/m, `- **Primary:** ${fields.primary_domain}`);
  }

  await writeFile(filePath, text, 'utf8');
  return { path: filePath, slug };
}

/**
 * createConnection(paths, fields)
 * Creates a new connection note from the Connection.md template.
 * fields: { node_a, node_b, connection_type, connection_strength,
 *           evidence_type, explanation, origin_session }
 * Returns: { path, slug }
 */
export async function createConnection(paths, fields) {
  const today = new Date().toISOString().slice(0, 10);
  const templatePath = join(paths.root, '06_Templates', 'Connection.md');
  let template = await readFile(templatePath, 'utf8');

  const rawSlug = `${slugify(fields.node_a || 'A')}--${slugify(fields.node_b || 'B')}`;
  const { path: filePath, slug } = await uniqueSlugPath(paths.connections, rawSlug);

  let text = template
    .replace(/\{\{date\}\}/g, today)
    .replace(/\{\{node_a\}\}/g, fields.node_a || '')
    .replace(/\{\{node_b\}\}/g, fields.node_b || '');

  const inlineUpdates = {
    node_a: fields.node_a || '',
    node_b: fields.node_b || '',
    connection_type: fields.connection_type || '',
    connection_strength: fields.connection_strength || 'low',
    evidence_type: fields.evidence_type || '',
    origin_session: fields.origin_session || today,
  };
  text = serializeMastery(text, inlineUpdates);

  // Fill YAML frontmatter
  text = text
    .replace(/^node_a:$/m, `node_a: ${fields.node_a || ''}`)
    .replace(/^node_b:$/m, `node_b: ${fields.node_b || ''}`)
    .replace(/^connection_type:$/m, `connection_type: ${fields.connection_type || ''}`)
    .replace(/^connection_strength: low$/m, `connection_strength: ${fields.connection_strength || 'low'}`)
    .replace(/^evidence_type:$/m, `evidence_type: ${fields.evidence_type || ''}`)
    .replace(/^origin_session:$/m, `origin_session: ${fields.origin_session || today}`);

  if (fields.explanation) {
    text = text.replace(
      /^\*Why does this connection exist\? What is the mechanism linking these two nodes\?\*$/m,
      fields.explanation,
    );
  }
  if (fields.connection_type) {
    text = text.replace(/^\*\*Type:\*\*$/m, `**Type:** ${fields.connection_type}`);
  }

  await writeFile(filePath, text, 'utf8');
  return { path: filePath, slug };
}

