// ─── Daily Flow handlers ──────────────────────────────────────────────────────

async function handleDailyFlowStart(res, paths) {
  const today = todayStr();

  // Run preflight checks
  const preflight = await runPreflightChecks(paths);

  // Build review queue (reuse same logic as handleReviewQueue)
  const masteryNotes = await loadAllMastery(paths);
  const reviewQueue = [];
  for (const note of masteryNotes) {
    const dueDate = note.inlineFields.next_review_due || '';
    if (!dueDate || dueDate > today) continue;
    const overdueDays = Math.max(0, Math.floor((new Date(today) - new Date(dueDate)) / 86400000));
    reviewQueue.push({
      topic_id: note.inlineFields.topic_id,
      domain: note.inlineFields.domain,
      level: Number(note.inlineFields.level) || 0,
      next_review_due: dueDate,
      overdue_days: overdueDays,
      retrieval_failure_count: Number(note.inlineFields.retrieval_failure_count) || 0,
      active_mode: note.inlineFields.active_mode || 'review',
      next_action: note.inlineFields.next_action || '',
    });
  }
  reviewQueue.sort((a, b) => b.overdue_days - a.overdue_days || b.retrieval_failure_count - a.retrieval_failure_count);

  // Scaffold today's session note if missing
  const sessionNotePath = join(paths.sessions, `${today}.md`);
  let sessionScaffolded = false;
  const existing = await findSessionNote(paths, today);
  if (!existing) {
    const dueReviews = masteryNotes
      .filter(n => { const d = n.inlineFields.next_review_due; return d && d <= today; })
      .map(n => ({
        topic_id: n.inlineFields.topic_id || basename(n.path, '.md'),
        domain: n.inlineFields.domain || '',
        next_review_due: n.inlineFields.next_review_due || today,
        retrieval_success_count: Number(n.inlineFields.retrieval_success_count) || 0,
        retrieval_failure_count: Number(n.inlineFields.retrieval_failure_count) || 0,
      }))
      .sort((a, b) => a.next_review_due.localeCompare(b.next_review_due));
    await ensureDir(paths.sessions);
    await writeFile(sessionNotePath, buildScaffoldContent(today, dueReviews), 'utf8');
    sessionScaffolded = true;
  }

  sendJson(res, {
    date: today,
    preflight,
    review_queue: reviewQueue,
    session_note_path: sessionNotePath,
    session_scaffolded: sessionScaffolded,
  });
}

async function handleNodeCreate(res, paths, body) {
  if (!body.node_name) return sendError(res, 'node_name is required', 400);
  const { path: filePath, slug } = await createNode(paths, { ...body, origin_session: body.origin_session || todayStr() });
  sendJson(res, { ok: true, path: filePath, slug });
}

async function handleConnectionCreate(res, paths, body) {
  if (!body.node_a || !body.node_b) return sendError(res, 'node_a and node_b are required', 400);
  const { path: filePath, slug } = await createConnection(paths, { ...body, origin_session: body.origin_session || todayStr() });
  sendJson(res, { ok: true, path: filePath, slug });
}

async function handleSessionLog(res, paths, body) {
  const today = todayStr();
  const date = body.date || today;
  const note = await findSessionNote(paths, date);
  if (!note) return sendError(res, `No session note found for ${date}`, 404);

  const updates = {};
  if (body.nodes_created !== undefined) updates.nodes_created = body.nodes_created;
  if (body.connections_created !== undefined) updates.connections_created = body.connections_created;
  if (body.friction_score !== undefined) updates.friction_score = body.friction_score;
  if (body.reflection !== undefined) updates.reflection = body.reflection;

  if (Object.keys(updates).length === 0) return sendError(res, 'No fields to update', 400);

  const rawText = await readFile(note.filePath, 'utf8');
  const updated = serializeMastery(rawText, updates);
  await writeFile(note.filePath, updated, 'utf8');
  sendJson(res, { ok: true });
}

