// daily-flow.js — Linear 6-step daily learning session view

const STEPS = ['Pre-Flight', 'Review', 'Node', 'Connection', 'Log', 'Summary'];

const INITIAL_STATE = {
  step: 0,
  date: null,
  preflight: null,
  reviewQueue: [],
  reviewIndex: 0,
  reviewResults: [],   // { topic_id, passed }
  nodesCreated: [],    // { slug, node_name }
  connectionsCreated: [],  // { slug, node_a, node_b }
  sessionPath: null,
  sessionScaffolded: false,
  loading: false,
  error: null,
};

// ─── Pure reducer ─────────────────────────────────────────────────────────────

function reduce(state, action) {
  switch (action.type) {
    case 'LOADING':
      return { ...state, loading: true, error: null };
    case 'ERROR':
      return { ...state, loading: false, error: action.error };
    case 'FLOW_STARTED':
      return {
        ...state,
        loading: false,
        date: action.date,
        preflight: action.preflight,
        reviewQueue: action.review_queue,
        sessionPath: action.session_note_path,
        sessionScaffolded: action.session_scaffolded,
      };
    case 'ADVANCE':
      return { ...state, step: state.step + 1, error: null };
    case 'REVIEW_RESULT':
      return {
        ...state,
        reviewResults: [...state.reviewResults, { topic_id: action.topic_id, passed: action.passed }],
        reviewIndex: state.reviewIndex + 1,
      };
    case 'NODE_CREATED':
      return {
        ...state,
        loading: false,
        nodesCreated: [...state.nodesCreated, { slug: action.slug, node_name: action.node_name }],
      };
    case 'CONNECTION_CREATED':
      return {
        ...state,
        loading: false,
        connectionsCreated: [...state.connectionsCreated, { slug: action.slug, node_a: action.node_a, node_b: action.node_b }],
      };
    case 'LOG_SAVED':
      return { ...state, loading: false };
    default:
      return state;
  }
}

// ─── Entry point ──────────────────────────────────────────────────────────────

export async function render(container, ctx) {
  let currentState = { ...INITIAL_STATE };

  function dispatch(action) {
    currentState = reduce(currentState, action);
    paint(container, currentState, dispatch, ctx);
  }

  // Boot: kick off the flow start
  paint(container, currentState, dispatch, ctx);
  dispatch({ type: 'LOADING' });
  try {
    const data = await ctx.api.post('/api/learn/daily-flow/start', {});
    dispatch({ type: 'FLOW_STARTED', ...data });
  } catch (err) {
    dispatch({ type: 'ERROR', error: err.message });
  }
}

// ─── Top-level painter ────────────────────────────────────────────────────────

function paint(container, state, dispatch, ctx) {
  container.innerHTML = `
    <div class="df-wrap">
      ${renderBreadcrumb(state.step)}
      <div class="df-body">
        ${renderStep(state, dispatch, ctx)}
      </div>
    </div>
  `;
  attachHandlers(container, state, dispatch, ctx);
}

// ─── Breadcrumb ───────────────────────────────────────────────────────────────

function renderBreadcrumb(step) {
  const crumbs = STEPS.map((label, i) => {
    const cls = i === step ? 'df-crumb df-crumb--active' : i < step ? 'df-crumb df-crumb--done' : 'df-crumb';
    return `<span class="${cls}">${label}</span>`;
  }).join('<span class="df-crumb-sep">›</span>');
  return `<nav class="df-breadcrumb">${crumbs}</nav>`;
}

// ─── Step dispatcher ──────────────────────────────────────────────────────────

function renderStep(state, dispatch, ctx) {
  if (state.loading && state.step === 0 && !state.preflight) {
    return `<div class="df-card"><p class="df-loading">Starting session…</p></div>`;
  }
  if (state.error) {
    return `
      <div class="df-card df-card--error">
        <p class="df-error-msg">${esc(state.error)}</p>
        <button class="btn" data-action="retry">Retry</button>
      </div>`;
  }
  switch (state.step) {
    case 0: return renderPreflight(state);
    case 1: return renderReview(state);
    case 2: return renderNodeBuilder(state);
    case 3: return renderConnectionBuilder(state);
    case 4: return renderSessionLog(state);
    case 5: return renderSummary(state, ctx);
    default: return `<div class="df-card"><p>Session complete.</p></div>`;
  }
}

// ─── Step 0: Pre-Flight ───────────────────────────────────────────────────────

function renderPreflight(state) {
  if (!state.preflight) return `<div class="df-card"><p class="df-loading">Checking…</p></div>`;

  const { passed, checks } = state.preflight;
  const rows = checks.map(c => {
    const icon = c.ok ? '✓' : '✗';
    const cls = c.ok ? 'df-check--ok' : 'df-check--fail';
    return `<li class="df-check ${cls}"><span class="df-check-icon">${icon}</span> ${esc(c.name.replace(/_/g, ' '))}${c.detail ? ` <span class="df-check-detail">— ${esc(c.detail)}</span>` : ''}</li>`;
  }).join('');

  const badge = passed
    ? `<p class="df-status df-status--ok">All checks passed. Ready to begin.</p>`
    : `<p class="df-status df-status--warn">Some checks failed — you can still continue.</p>`;

  return `
    <div class="df-card">
      <h2 class="df-step-title">Pre-Flight Check</h2>
      <ul class="df-checklist">${rows}</ul>
      ${badge}
      <div class="df-actions">
        <button class="btn btn--primary" data-action="advance">Begin Session</button>
      </div>
    </div>`;
}

// ─── Step 1: Review Queue ─────────────────────────────────────────────────────

function renderReview(state) {
  const { reviewQueue, reviewIndex } = state;

  if (reviewQueue.length === 0) {
    return `
      <div class="df-card">
        <h2 class="df-step-title">Review Queue</h2>
        <p class="df-empty">No items due for review today.</p>
        <div class="df-actions">
          <button class="btn btn--primary" data-action="advance">Next: Build Node</button>
        </div>
      </div>`;
  }

  if (reviewIndex >= reviewQueue.length) {
    const passed = state.reviewResults.filter(r => r.passed).length;
    return `
      <div class="df-card">
        <h2 class="df-step-title">Review Queue</h2>
        <p class="df-status df-status--ok">Reviewed ${reviewQueue.length} item${reviewQueue.length !== 1 ? 's' : ''} — ${passed} passed.</p>
        <div class="df-actions">
          <button class="btn btn--primary" data-action="advance">Next: Build Node</button>
        </div>
      </div>`;
  }

  const item = reviewQueue[reviewIndex];
  const progress = `${reviewIndex + 1} / ${reviewQueue.length}`;
  const overdueBadge = item.overdue_days > 0
    ? `<span class="df-badge df-badge--warn">${item.overdue_days}d overdue</span>`
    : `<span class="df-badge">due today</span>`;

  return `
    <div class="df-card">
      <h2 class="df-step-title">Review Queue <span class="df-progress">${progress}</span></h2>
      <div class="df-review-item">
        <p class="df-review-topic">${esc(item.topic_id || '—')}</p>
        <p class="df-review-meta">${esc(item.domain || '')} · Level ${item.level} ${overdueBadge}</p>
        <p class="df-review-hint">Retrieve from memory before checking notes.</p>
      </div>
      <div class="df-actions">
        <button class="btn btn--ok" data-action="review-pass" data-topic="${esc(item.topic_id)}">Pass</button>
        <button class="btn btn--fail" data-action="review-fail" data-topic="${esc(item.topic_id)}">Fail</button>
        <button class="btn btn--ghost" data-action="review-skip-all">Skip remaining</button>
      </div>
    </div>`;
}

// ─── Step 2: Node Builder ─────────────────────────────────────────────────────

function renderNodeBuilder(state) {
  const savedCount = state.nodesCreated.length;
  const savedList = savedCount > 0
    ? `<ul class="df-saved-list">${state.nodesCreated.map(n => `<li>✓ ${esc(n.node_name)}</li>`).join('')}</ul>`
    : '';

  return `
    <div class="df-card">
      <h2 class="df-step-title">Build a Node</h2>
      ${savedList}
      ${state.loading ? `<p class="df-loading">Saving…</p>` : ''}
      ${state.error ? `<p class="df-error-msg">${esc(state.error)}</p>` : ''}
      <form class="df-form" data-form="node">
        <label class="df-label">Concept name <span class="df-req">*</span>
          <input class="df-input" name="node_name" required placeholder="e.g. Working Memory" />
        </label>
        <label class="df-label">Primary domain <span class="df-req">*</span>
          <input class="df-input" name="primary_domain" required placeholder="e.g. Cognitive Science" />
        </label>
        <label class="df-label">Definition
          <textarea class="df-textarea" name="definition" rows="2" placeholder="Simple, clear. One or two sentences."></textarea>
        </label>
        <label class="df-label">Core mechanism
          <textarea class="df-textarea" name="core_mechanism" rows="2" placeholder="How does it work? Input → process → output."></textarea>
        </label>
        <label class="df-label">Why it matters
          <textarea class="df-textarea" name="why_it_matters" rows="2" placeholder="Useful across what contexts?"></textarea>
        </label>
        <label class="df-label">Example
          <textarea class="df-textarea" name="example" rows="2" placeholder="One concrete, real-world instance."></textarea>
        </label>
        <label class="df-label">Confidence (1–5)
          <input class="df-input df-input--sm" name="confidence_rating" type="number" min="1" max="5" value="3" />
        </label>
        <div class="df-actions">
          <button class="btn btn--primary" type="submit">Save Node</button>
          <button class="btn btn--ghost" type="button" data-action="advance">Skip → Connection</button>
        </div>
      </form>
    </div>`;
}

// ─── Step 3: Connection Builder ───────────────────────────────────────────────

function renderConnectionBuilder(state) {
  const { nodesCreated, connectionsCreated } = state;
  const savedCount = connectionsCreated.length;
  const savedList = savedCount > 0
    ? `<ul class="df-saved-list">${connectionsCreated.map(c => `<li>✓ ${esc(c.node_a)} → ${esc(c.node_b)}</li>`).join('')}</ul>`
    : '';

  // Build datalist options from nodes created this session
  const datalistOptions = nodesCreated.map(n => `<option value="${esc(n.node_name)}">`).join('');

  const CONNECTION_TYPES = ['Cause', 'Dependency', 'Feedback Loop', 'Tradeoff', 'Reinforcement', 'Historical Analogy', 'Structural Similarity', 'Constraint', 'Incentive Relationship'];
  const typeOptions = CONNECTION_TYPES.map(t => `<option value="${t}">${t}</option>`).join('');
  const strengthOptions = ['low', 'medium', 'high'].map(s => `<option value="${s}">${s}</option>`).join('');

  return `
    <div class="df-card">
      <h2 class="df-step-title">Create a Connection</h2>
      ${savedList}
      ${state.loading ? `<p class="df-loading">Saving…</p>` : ''}
      ${state.error ? `<p class="df-error-msg">${esc(state.error)}</p>` : ''}
      <datalist id="df-node-list">${datalistOptions}</datalist>
      <form class="df-form" data-form="connection">
        <label class="df-label">Node A <span class="df-req">*</span>
          <input class="df-input" name="node_a" required list="df-node-list" placeholder="Start typing a node name…" />
        </label>
        <label class="df-label">Node B <span class="df-req">*</span>
          <input class="df-input" name="node_b" required list="df-node-list" placeholder="Start typing a node name…" />
        </label>
        <label class="df-label">Connection type
          <select class="df-select" name="connection_type">
            <option value="">— choose —</option>
            ${typeOptions}
          </select>
        </label>
        <label class="df-label">Strength
          <select class="df-select" name="connection_strength">
            ${strengthOptions}
          </select>
        </label>
        <label class="df-label">Evidence type
          <input class="df-input" name="evidence_type" placeholder="e.g. theoretical, empirical, observed" />
        </label>
        <label class="df-label">Explanation
          <textarea class="df-textarea" name="explanation" rows="3" placeholder="Why does this connection exist?"></textarea>
        </label>
        <div class="df-actions">
          <button class="btn btn--primary" type="submit">Save Connection</button>
          <button class="btn btn--ghost" type="button" data-action="add-another-connection">Add Another</button>
          <button class="btn btn--ghost" type="button" data-action="advance">Next: Log Session</button>
        </div>
      </form>
    </div>`;
}

// ─── Step 4: Session Log ──────────────────────────────────────────────────────

function renderSessionLog(state) {
  return `
    <div class="df-card">
      <h2 class="df-step-title">Log Session</h2>
      ${state.loading ? `<p class="df-loading">Saving…</p>` : ''}
      ${state.error ? `<p class="df-error-msg">${esc(state.error)}</p>` : ''}
      <form class="df-form" data-form="log">
        <label class="df-label">Friction score (1 = smooth, 5 = struggled)
          <input class="df-input df-input--sm" name="friction_score" type="number" min="1" max="5" value="3" />
        </label>
        <label class="df-label">Reflection <span class="df-hint">(optional)</span>
          <textarea class="df-textarea" name="reflection" rows="3" placeholder="What worked? What didn't? Any surprises?"></textarea>
        </label>
        <div class="df-actions">
          <button class="btn btn--primary" type="submit">Save &amp; Finish</button>
        </div>
      </form>
    </div>`;
}

// ─── Step 5: Summary ──────────────────────────────────────────────────────────

function renderSummary(state, ctx) {
  const { reviewResults, nodesCreated, connectionsCreated, sessionPath, date } = state;
  const passed = reviewResults.filter(r => r.passed).length;
  const vaultName = 'My_Data';
  const relPath = sessionPath
    ? sessionPath.replace(/\\/g, '/').replace(/.*11_Learning\//, '11_Learning/')
    : '';
  const obsidianLink = relPath
    ? `obsidian://open?vault=${encodeURIComponent(vaultName)}&file=${encodeURIComponent(relPath)}`
    : null;

  const nodeList = nodesCreated.length
    ? `<ul class="df-saved-list">${nodesCreated.map(n => `<li>${esc(n.node_name)}</li>`).join('')}</ul>`
    : `<p class="df-empty">None created this session.</p>`;

  const connList = connectionsCreated.length
    ? `<ul class="df-saved-list">${connectionsCreated.map(c => `<li>${esc(c.node_a)} → ${esc(c.node_b)}</li>`).join('')}</ul>`
    : `<p class="df-empty">None created this session.</p>`;

  return `
    <div class="df-card">
      <h2 class="df-step-title">Session Complete — ${esc(date || '')}</h2>
      <div class="df-summary-grid">
        <div class="df-summary-cell">
          <span class="df-summary-num">${reviewResults.length}</span>
          <span class="df-summary-label">reviewed</span>
          <span class="df-summary-sub">${passed} passed</span>
        </div>
        <div class="df-summary-cell">
          <span class="df-summary-num">${nodesCreated.length}</span>
          <span class="df-summary-label">nodes</span>
        </div>
        <div class="df-summary-cell">
          <span class="df-summary-num">${connectionsCreated.length}</span>
          <span class="df-summary-label">connections</span>
        </div>
      </div>
      <h3 class="df-sub-heading">Nodes built</h3>
      ${nodeList}
      <h3 class="df-sub-heading">Connections made</h3>
      ${connList}
      ${obsidianLink ? `
        <div class="df-actions df-actions--mt">
          <a class="btn btn--secondary" href="${obsidianLink}">Open session note in Obsidian</a>
        </div>` : ''}
      <div class="df-actions">
        <button class="btn btn--ghost" data-action="go-observatory">Back to Observatory</button>
      </div>
    </div>`;
}

// ─── Event handlers ───────────────────────────────────────────────────────────

function attachHandlers(container, state, dispatch, ctx) {
  // Generic action buttons
  container.querySelectorAll('[data-action]').forEach(el => {
    el.addEventListener('click', (e) => {
      const action = e.currentTarget.dataset.action;
      handleAction(action, e.currentTarget, state, dispatch, ctx);
    });
  });

  // Form submissions
  container.querySelectorAll('[data-form]').forEach(form => {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      handleFormSubmit(form.dataset.form, form, state, dispatch, ctx);
    });
  });
}

function handleAction(action, el, state, dispatch, ctx) {
  switch (action) {
    case 'advance':
      dispatch({ type: 'ADVANCE' });
      break;
    case 'retry':
      // Re-render from current step, clear error
      dispatch({ type: 'ERROR', error: null });
      break;
    case 'review-pass':
      submitReview(el.dataset.topic, true, state, dispatch, ctx);
      break;
    case 'review-fail':
      submitReview(el.dataset.topic, false, state, dispatch, ctx);
      break;
    case 'review-skip-all':
      dispatch({ type: 'ADVANCE' });
      break;
    case 'add-another-connection':
      // Stay on connection step — just clear form (re-render)
      dispatch({ type: 'CONNECTION_CREATED', slug: '', node_a: '', node_b: '' });
      break;
    case 'go-observatory':
      ctx.navigate('observatory');
      break;
  }
}

async function submitReview(topicId, passed, state, dispatch, ctx) {
  try {
    await ctx.api.post('/api/learn/check/submit', {
      topic_id: topicId,
      passed,
      mode: 'recall',
      response_text: '',
    });
  } catch {
    // Non-fatal — record result locally regardless
  }
  dispatch({ type: 'REVIEW_RESULT', topic_id: topicId, passed });

  // Auto-advance when queue exhausted
  const nextIndex = state.reviewIndex + 1;
  if (nextIndex >= state.reviewQueue.length) {
    // Let the re-render show the "all done" screen; user clicks Next
  }
}

async function handleFormSubmit(formType, form, state, dispatch, ctx) {
  const data = Object.fromEntries(new FormData(form).entries());

  switch (formType) {
    case 'node': {
      if (!data.node_name || !data.primary_domain) return;
      dispatch({ type: 'LOADING' });
      try {
        const result = await ctx.api.post('/api/learn/node/create', {
          ...data,
          origin_session: state.date,
          confidence_rating: Number(data.confidence_rating) || 0,
        });
        dispatch({ type: 'NODE_CREATED', slug: result.slug, node_name: data.node_name });
        form.reset();
      } catch (err) {
        dispatch({ type: 'ERROR', error: err.message });
      }
      break;
    }
    case 'connection': {
      if (!data.node_a || !data.node_b) return;
      dispatch({ type: 'LOADING' });
      try {
        const result = await ctx.api.post('/api/learn/connection/create', {
          ...data,
          origin_session: state.date,
        });
        dispatch({ type: 'CONNECTION_CREATED', slug: result.slug, node_a: data.node_a, node_b: data.node_b });
        form.reset();
        // Advance automatically after first successful connection save
        dispatch({ type: 'ADVANCE' });
      } catch (err) {
        dispatch({ type: 'ERROR', error: err.message });
      }
      break;
    }
    case 'log': {
      dispatch({ type: 'LOADING' });
      try {
        await ctx.api.patch('/api/learn/session/log', {
          date: state.date,
          nodes_created: state.nodesCreated.length,
          connections_created: state.connectionsCreated.length,
          friction_score: Number(data.friction_score) || null,
          reflection: data.reflection || '',
        });
        dispatch({ type: 'LOG_SAVED' });
        dispatch({ type: 'ADVANCE' });
      } catch (err) {
        dispatch({ type: 'ERROR', error: err.message });
      }
      break;
    }
  }
}

// ─── Utility ──────────────────────────────────────────────────────────────────

function esc(str) {
  return String(str ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

