// daily-flow.js — Linear 6-step daily learning session view

const STEPS = ['Pre-Flight', 'Review', 'Node', 'Connection', 'Log', 'Summary'];

const INITIAL_STATE = {
  step: 0,
  date: null,
  preflight: null,
  reviewQueue: [],
  reviewIndex: 0,
  reviewResults: [],   // { topic_id, passed }
  nodesCreated: [],    // { slug, node_name }
