// daily-flow.js — Full V1 session engine (Learning Session Scaffold Flow V1)
// Steps: Start | Warm-Up | Content | Example | Node | Interweave | Check | Reflect | Schedule | Done

const STEPS = ['Start', 'Warm-Up', 'Content', 'Example', 'Node', 'Interweave', 'Check', 'Reflect', 'Schedule', 'Done'];

// Steps skipped per session mode
const MODE_SKIP = {
  standard:     new Set(),
  light:        new Set([2, 3, 6]),    // skip Content, Example, Check
  interweave:   new Set([2, 3]),       // skip Content, Example (focus on connections)
  'review-heavy': new Set([2, 3, 6]), // skip Content, Example, Check
};

const INITIAL_STATE = {
  step: 0,
  sessionMode: 'standard',
  sessionTopic: null,     // { topic_id, domain, level } — chosen at Start
  date: null,
  preflight: null,
  reviewQueue: [],
  reviewIndex: 0,
  reviewResults: [],
  contentInput: '',
  exampleLevel: 'A',      // A/B/C based on mastery
  exampleText: '',
  nodesCreated: [],       // { slug, node_name }
  connectionsCreated: [], // { slug, node_a, node_b }
  checkQuestion: null,    // { prompt, type } from /api/learn/check/generate
  checkAnswer: '',
  checkResult: null,      // 'pass' | 'fail' | 'partial'
  reflectionData: null,
  sessionPath: null,
  sessionScaffolded: false,
  loading: false,
  error: null,
};

// ─── Pure reducer ─────────────────────────────────────────────────────────────

function reduce(state, action) {
  switch (action.type) {
    case 'LOADING':
      return { ...state, loading: true, error: null };
    case 'ERROR':
      return { ...state, loading: false, error: action.error };
    case 'CLEAR_ERROR':
      return { ...state, error: null };
    case 'FLOW_STARTED':
      return {
        ...state,
        loading: false,
        date: action.date,
        preflight: action.preflight,
        reviewQueue: action.review_queue,
        sessionPath: action.session_note_path,
        sessionScaffolded: action.session_scaffolded,
      };
    case 'SET_MODE':
      return { ...state, sessionMode: action.mode };
    case 'SET_TOPIC':
      return {
        ...state,
        sessionTopic: action.topic,
        exampleLevel: levelToExampleLevel(action.topic?.level ?? 0),
      };
    case 'ADVANCE': {
      const skip = MODE_SKIP[state.sessionMode] || new Set();
      let next = state.step + 1;
      while (skip.has(next) && next < STEPS.length) next++;
      return { ...state, step: next, error: null };
    }
    case 'REVIEW_RESULT':
      return {
        ...state,
        reviewResults: [...state.reviewResults, { topic_id: action.topic_id, passed: action.passed }],
        reviewIndex: state.reviewIndex + 1,
      };
    case 'SET_CONTENT':
      return { ...state, contentInput: action.value };
    case 'SET_EXAMPLE':
      return { ...state, exampleText: action.value };
    case 'NODE_CREATED':
      return { ...state, loading: false, nodesCreated: [...state.nodesCreated, { slug: action.slug, node_name: action.node_name }] };
    case 'CONNECTION_CREATED':
      return { ...state, loading: false, connectionsCreated: [...state.connectionsCreated, { slug: action.slug, node_a: action.node_a, node_b: action.node_b }] };
    case 'CHECK_LOADED':
      return { ...state, loading: false, checkQuestion: action.question };
    case 'CHECK_ANSWERED':
      return { ...state, checkAnswer: action.answer };
    case 'CHECK_RESULT':
      return { ...state, loading: false, checkResult: action.result };
    case 'LOG_SAVED':
      return { ...state, loading: false };
    default:
      return state;
  }
}

function levelToExampleLevel(level) {
  if (level < 2) return 'A';
  if (level < 4) return 'B';
  return 'C';
}

// ─── Entry point ──────────────────────────────────────────────────────────────

export async function render(container, ctx) {
  let currentState = { ...INITIAL_STATE };

  function dispatch(action) {
    currentState = reduce(currentState, action);
    paint(container, currentState, dispatch, ctx);
  }

  paint(container, currentState, dispatch, ctx);
  dispatch({ type: 'LOADING' });
  try {
    const data = await ctx.api.post('/api/learn/daily-flow/start', {});
    dispatch({ type: 'FLOW_STARTED', ...data });
  } catch (err) {
    dispatch({ type: 'ERROR', error: err.message });
  }
}

// ─── Top-level painter ────────────────────────────────────────────────────────

function paint(container, state, dispatch, ctx) {
  container.innerHTML = `
    <div class="df-wrap">
      ${renderBreadcrumb(state)}
      <div class="df-body">
        ${state.loading && state.step === 0 && !state.preflight
          ? `<div class="df-card"><p class="df-loading">Starting session…</p></div>`
          : state.error
          ? renderError(state, dispatch)
          : renderStep(state, dispatch, ctx)}
      </div>
    </div>`;
  attachHandlers(container, state, dispatch, ctx);
}

function renderError(state) {
  return `
    <div class="df-card df-card--error">
      <p class="df-error-msg">${esc(state.error)}</p>
      <button class="btn" data-action="clear-error">Dismiss</button>
    </div>`;
}

// ─── Breadcrumb ───────────────────────────────────────────────────────────────

function renderBreadcrumb(state) {
  const skip = MODE_SKIP[state.sessionMode] || new Set();
  const crumbs = STEPS.map((label, i) => {
    if (skip.has(i)) return '';
    const cls = i === state.step ? 'df-crumb df-crumb--active' : i < state.step ? 'df-crumb df-crumb--done' : 'df-crumb';
    return `<span class="${cls}">${label}</span>`;
  }).filter(Boolean).join('<span class="df-crumb-sep">›</span>');
  return `<nav class="df-breadcrumb">${crumbs}</nav>`;
}

// ─── Step dispatcher ──────────────────────────────────────────────────────────

function renderStep(state, dispatch, ctx) {
  switch (state.step) {
    case 0: return renderStart(state, dispatch);
    case 1: return renderWarmUp(state, dispatch, ctx);
    case 2: return renderContent(state, dispatch, ctx);
    case 3: return renderExample(state, dispatch);
    case 4: return renderNodeBuilder(state, dispatch, ctx);
    case 5: return renderInterweave(state, dispatch, ctx);
    case 6: return renderCheck(state, dispatch, ctx);
    case 7: return renderReflect(state, dispatch);
    case 8: return renderSchedule(state, dispatch);
    case 9: return renderDone(state, ctx);
    default: return `<div class="df-card"><p>Session complete.</p></div>`;
  }
}

// ─── Step 0: Start / Pre-Flight ───────────────────────────────────────────────

function renderStart(state) {
  if (!state.preflight) return `<div class="df-card"><p class="df-loading">Running checks…</p></div>`;

  const { checks } = state.preflight;
  const rows = checks.map(c => {
    const icon = c.ok ? '✓' : '✗';
    const cls = c.ok ? 'df-check--ok' : 'df-check--fail';
    return `<li class="df-check ${cls}"><span class="df-check-icon">${icon}</span> ${esc(c.name.replace(/_/g, ' '))}${c.detail ? ` <span class="df-check-detail">— ${esc(c.detail)}</span>` : ''}</li>`;
  }).join('');

  const MODES = [
    { id: 'standard', label: 'Standard Build', desc: 'Full 8-step session — review, content, node, connections, check' },
    { id: 'light', label: 'Light', desc: 'Review + node update + scheduling only' },
    { id: 'interweave', label: 'Interweave', desc: 'Focus on connecting existing nodes' },
    { id: 'review-heavy', label: 'Review-Heavy', desc: 'Clear the overdue queue' },
  ];

  const modeOptions = MODES.map(m => `
    <label class="df-mode-option ${state.sessionMode === m.id ? 'df-mode-option--active' : ''}">
      <input type="radio" name="session_mode" value="${m.id}" ${state.sessionMode === m.id ? 'checked' : ''} />
      <span class="df-mode-label">${m.label}</span>
      <span class="df-mode-desc">${m.desc}</span>
    </label>`).join('');

  // Topic picker: review queue items + free-form input
  const topicOptions = state.reviewQueue.length
    ? state.reviewQueue.map(i => `<option value="${esc(i.topic_id)}">${esc(i.topic_id)} (${esc(i.domain)}, L${i.level})</option>`).join('')
    : '';

  return `
    <div class="df-card">
      <h2 class="df-step-title">Session Start — ${esc(state.date || '')}</h2>
      <ul class="df-checklist">${rows}</ul>
      <h3 class="df-sub-heading">Session mode</h3>
      <div class="df-mode-grid" data-group="mode">${modeOptions}</div>
      <h3 class="df-sub-heading">Topic for today</h3>
      <p class="df-hint">Select from your review queue or type a new topic.</p>
      <select class="df-select" id="df-topic-select">
        <option value="">— type or select —</option>
        ${topicOptions}
      </select>
      <input class="df-input df-input--mt" id="df-topic-free" placeholder="Or type a topic name…" />
      <div class="df-actions">
        <button class="btn btn--primary" data-action="start-session">Begin Session</button>
      </div>
    </div>`;
}

// ─── Step 1: Review Warm Start ────────────────────────────────────────────────

function renderWarmUp(state, dispatch, ctx) {
  const { reviewQueue, reviewIndex, sessionTopic } = state;

  if (reviewQueue.length === 0) {
    return `
      <div class="df-card">
        <h2 class="df-step-title">Warm-Up Review</h2>
        <p class="df-empty">No items due today — your queue is clear.</p>
        <div class="df-actions">
          <button class="btn btn--primary" data-action="advance">Next →</button>
        </div>
      </div>`;
  }

  if (reviewIndex >= reviewQueue.length) {
    const passed = state.reviewResults.filter(r => r.passed).length;
    return `
      <div class="df-card">
        <h2 class="df-step-title">Warm-Up Review</h2>
        <p class="df-status df-status--ok">Reviewed ${reviewQueue.length} item${reviewQueue.length !== 1 ? 's' : ''} — ${passed} passed.</p>
        <p class="df-hint">Misconceptions spotted above will feed into today's node work.</p>
        <div class="df-actions">
          <button class="btn btn--primary" data-action="advance">Next →</button>
        </div>
      </div>`;
  }

  const item = reviewQueue[reviewIndex];
  const progress = `${reviewIndex + 1} / ${reviewQueue.length}`;
  const overdueBadge = item.overdue_days > 0
    ? `<span class="df-badge df-badge--warn">${item.overdue_days}d overdue</span>`
    : `<span class="df-badge">due today</span>`;

  return `
    <div class="df-card">
      <h2 class="df-step-title">Warm-Up Review <span class="df-progress">${progress}</span></h2>
      <div class="df-review-item">
        <p class="df-review-topic">${esc(item.topic_id || '—')}</p>
        <p class="df-review-meta">${esc(item.domain || '')} · Level ${item.level} ${overdueBadge}</p>
        <p class="df-review-prompt">Explain from memory: <em>What is this and how does it work?</em></p>
        <p class="df-hint">Do not open notes yet. Retrieve first, then score your recall.</p>
      </div>
      <div class="df-actions">
        <button class="btn btn--ok" data-action="review-pass" data-topic="${esc(item.topic_id)}">Pass — recalled well</button>
        <button class="btn btn--fail" data-action="review-fail" data-topic="${esc(item.topic_id)}">Fail — gaps found</button>
        <button class="btn btn--ghost" data-action="advance">Skip queue →</button>
      </div>
    </div>`;
}

// ─── Step 2: Content Input ────────────────────────────────────────────────────

function renderContent(state, dispatch, ctx) {
  const topic = state.sessionTopic?.topic_id || 'your topic';
  return `
    <div class="df-card">
      <h2 class="df-step-title">Content Input</h2>
      <p class="df-hint">Read one small content block — article excerpt, abstract, diagram note, or case. Keep it narrow enough to support one node.</p>
      <div class="df-framing-questions">
        <p class="df-framing-q">❶ What is <strong>${esc(topic)}</strong>?</p>
        <p class="df-framing-q">❷ How does it work? (Input → process → output)</p>
        <p class="df-framing-q">❸ Why does it matter across contexts?</p>
      </div>
      <label class="df-label">Paste or summarise your content here
        <textarea class="df-textarea df-textarea--lg" id="df-content-input" rows="6"
          placeholder="Paste an abstract, excerpt, or your own summary of the source material…">${esc(state.contentInput)}</textarea>
      </label>
      ${state.loading ? `<p class="df-loading">Loading resources…</p>` : ''}
      <div class="df-actions">
        <button class="btn btn--ghost" data-action="search-resources">Search related papers</button>
        <button class="btn btn--primary" data-action="save-content">Save &amp; Continue →</button>
        <button class="btn btn--ghost" data-action="advance">Skip →</button>
      </div>
    </div>`;
}

// ─── Step 3: Leveled Worked Example ──────────────────────────────────────────

function renderExample(state) {
  const level = state.exampleLevel;
  const topic = state.sessionTopic?.topic_id || 'your topic';

  const LEVEL_CONFIG = {
    A: {
      badge: 'Level A — Worked Example',
      intro: 'You are new to this node. Write a complete worked example showing the full mechanism. Include: definition → how it works → near miss or common confusion.',
      prompt: `Write a complete worked example for <strong>${esc(topic)}</strong>:\n• State what it is\n• Show the mechanism chain (input → process → output)\n• Give one real-world instance\n• Note one common misconception`,
    },
    B: {
      badge: 'Level B — Guided Completion',
      intro: 'You have some familiarity. Complete the partial framework below, filling in the mechanism links.',
      prompt: `Complete this framework for <strong>${esc(topic)}</strong>:\n• It is a type of: ___\n• It works by: ___\n• The key input is: ___ and the output is: ___\n• It matters because: ___\n• It connects to [older node] because: ___`,
    },
    C: {
      badge: 'Level C — Independent Reconstruction',
      intro: 'You can explain this node with light support. Reconstruct it entirely from memory.',
      prompt: `Reconstruct <strong>${esc(topic)}</strong> from memory. Cover:\n• Definition\n• Mechanism\n• At least one cross-domain application\n• One node it depends on and one node that depends on it`,
    },
  };

  const cfg = LEVEL_CONFIG[level];
  return `
    <div class="df-card">
      <h2 class="df-step-title">Worked Example <span class="df-badge df-badge--level">${cfg.badge}</span></h2>
      <p class="df-hint">${cfg.intro}</p>
      <div class="df-framing-questions"><p class="df-framing-q">${cfg.prompt}</p></div>
      <label class="df-label">Your worked example
        <textarea class="df-textarea df-textarea--lg" id="df-example-input" rows="7"
          placeholder="Write your worked example here…">${esc(state.exampleText)}</textarea>
      </label>
      <p class="df-hint-sm">This will pre-fill the Example field in the Node Builder.</p>
      <div class="df-actions">
        <button class="btn btn--primary" data-action="save-example">Save &amp; Continue →</button>
        <button class="btn btn--ghost" data-action="advance">Skip →</button>
      </div>
    </div>`;
}

// ─── Step 4: Node Build ───────────────────────────────────────────────────────

function renderNodeBuilder(state) {
  const savedList = state.nodesCreated.length
    ? `<ul class="df-saved-list">${state.nodesCreated.map(n => `<li>✓ ${esc(n.node_name)}</li>`).join('')}</ul>`
    : '';

  const prefillExample = esc(state.exampleText || '');
  const prefillTopic = esc(state.sessionTopic?.topic_id || '');
  const prefillDomain = esc(state.sessionTopic?.domain || '');

  return `
    <div class="df-card">
      <h2 class="df-step-title">Node Build</h2>
      <p class="df-hint">One node per session. Keep it reusable and explainable. If the concept is too broad, shrink it.</p>
      ${savedList}
      ${state.loading ? `<p class="df-loading">Saving…</p>` : ''}
      ${state.error ? `<p class="df-error-msg">${esc(state.error)}</p>` : ''}
      <form class="df-form" data-form="node">
        <label class="df-label">Concept name <span class="df-req">*</span>
          <input class="df-input" name="node_name" required value="${prefillTopic}" placeholder="e.g. Working Memory" />
        </label>
        <label class="df-label">Primary domain <span class="df-req">*</span>
          <input class="df-input" name="primary_domain" required value="${prefillDomain}" placeholder="e.g. Cognitive Science" />
        </label>
        <label class="df-label">Definition <span class="df-hint-sm">(simple, 1–2 sentences)</span>
          <textarea class="df-textarea" name="definition" rows="2" placeholder="What is this?"></textarea>
        </label>
        <label class="df-label">Core mechanism
          <textarea class="df-textarea" name="core_mechanism" rows="2" placeholder="How does it work? Input → process → output."></textarea>
        </label>
        <label class="df-label">Why it matters
          <textarea class="df-textarea" name="why_it_matters" rows="2" placeholder="Why is this useful across multiple contexts?"></textarea>
        </label>
        <label class="df-label">Example <span class="df-hint-sm">(pre-filled from worked example above)</span>
          <textarea class="df-textarea" name="example" rows="3">${prefillExample}</textarea>
        </label>
        <label class="df-label">Confidence (1–5)
          <input class="df-input df-input--sm" name="confidence_rating" type="number" min="1" max="5" value="3" />
        </label>
        <div class="df-actions">
          <button class="btn btn--primary" type="submit">Save Node</button>
          <button class="btn btn--ghost" type="button" data-action="advance">Skip →</button>
        </div>
      </form>
    </div>`;
}

// ─── Step 5: Interweaving Pass ────────────────────────────────────────────────

function renderInterweave(state) {
  const savedList = state.connectionsCreated.length
    ? `<ul class="df-saved-list">${state.connectionsCreated.map(c => `<li>✓ ${esc(c.node_a)} → ${esc(c.node_b)}</li>`).join('')}</ul>`
    : '';

  const PROMPTS = [
    'What older node does this connect to? What is the shared mechanism?',
    'What depends on this node? What breaks if it weakens?',
    'Is this a cause, dependency, tradeoff, feedback loop, or constraint?',
    'Where does the same pattern appear in another domain?',
  ];
  const promptList = PROMPTS.map(p => `<li class="df-prompt-item">→ ${p}</li>`).join('');

  const nodeOptions = state.nodesCreated.map(n => `<option value="${esc(n.node_name)}">`).join('');
  const CONNECTION_TYPES = ['Cause', 'Dependency', 'Feedback Loop', 'Tradeoff', 'Reinforcement', 'Historical Analogy', 'Structural Similarity', 'Constraint', 'Incentive Relationship'];
  const typeOptions = CONNECTION_TYPES.map(t => `<option value="${t}">${t}</option>`).join('');
  const target = `${state.connectionsCreated.length >= 2 ? '✓ ' : ''}2–4 connections per session`;

  return `
    <div class="df-card">
      <h2 class="df-step-title">Interweaving Pass</h2>
      <p class="df-hint">This is the most important step. Use these prompts to find real connections — not just surface similarity.</p>
      <ul class="df-prompt-list">${promptList}</ul>
      <p class="df-target">Target: ${target}</p>
      ${savedList}
      ${state.loading ? `<p class="df-loading">Saving…</p>` : ''}
      ${state.error ? `<p class="df-error-msg">${esc(state.error)}</p>` : ''}
      <datalist id="df-node-list">${nodeOptions}</datalist>
      <form class="df-form" data-form="connection">
        <label class="df-label">Node A <span class="df-req">*</span>
          <input class="df-input" name="node_a" required list="df-node-list" placeholder="Start typing…" />
        </label>
        <label class="df-label">Node B <span class="df-req">*</span>
          <input class="df-input" name="node_b" required list="df-node-list" placeholder="Start typing…" />
        </label>
        <label class="df-label">Connection type
          <select class="df-select" name="connection_type">
            <option value="">— choose —</option>${typeOptions}
          </select>
        </label>
        <label class="df-label">Explanation — <em>Why does this connection exist? What is the mechanism?</em>
          <textarea class="df-textarea" name="explanation" rows="3"></textarea>
        </label>
        <div class="df-actions">
          <button class="btn btn--primary" type="submit">Save Connection</button>
          <button class="btn btn--ghost" type="button" data-action="advance">Done connecting →</button>
        </div>
      </form>
    </div>`;
}

// ─── Step 6: Knowledge Check ──────────────────────────────────────────────────

function renderCheck(state, dispatch, ctx) {
  const topic = state.sessionTopic?.topic_id;

  if (!topic) {
    return `
      <div class="df-card">
        <h2 class="df-step-title">Knowledge Check</h2>
        <p class="df-empty">No topic selected — skipping check.</p>
        <div class="df-actions"><button class="btn btn--primary" data-action="advance">Next →</button></div>
      </div>`;
  }

  if (!state.checkQuestion && !state.loading) {
    return `
      <div class="df-card">
        <h2 class="df-step-title">Knowledge Check</h2>
        <p class="df-hint">One check per session. Answer from memory before reading notes.</p>
        <div class="df-actions">
          <button class="btn btn--primary" data-action="load-check">Generate Check Question</button>
          <button class="btn btn--ghost" data-action="advance">Skip →</button>
        </div>
      </div>`;
  }

  if (state.loading) return `<div class="df-card"><p class="df-loading">Generating question…</p></div>`;

  if (state.checkResult) {
    const icon = state.checkResult === 'pass' ? '✓' : state.checkResult === 'partial' ? '~' : '✗';
    const cls = state.checkResult === 'pass' ? 'df-status--ok' : state.checkResult === 'partial' ? 'df-status--warn' : 'df-status--fail';
    return `
      <div class="df-card">
        <h2 class="df-step-title">Knowledge Check</h2>
        <p class="df-status ${cls}">${icon} ${state.checkResult.charAt(0).toUpperCase() + state.checkResult.slice(1)}</p>
        <p class="df-hint">Result recorded. Mastery counters updated.</p>
        <div class="df-actions"><button class="btn btn--primary" data-action="advance">Next →</button></div>
      </div>`;
  }

  const q = state.checkQuestion;
  const CHECK_TYPES = { define: 'Define it', cause_chain: 'Explain the cause chain', apply: 'Apply to a mini case', contrast: 'Contrast with a similar node', predict: 'Predict what happens if one variable changes', transfer: 'Explain where this appears in another domain' };
  const typeLabel = CHECK_TYPES[q?.type] || q?.type || 'Recall';

  return `
    <div class="df-card">
      <h2 class="df-step-title">Knowledge Check <span class="df-badge">${esc(typeLabel)}</span></h2>
      <p class="df-review-prompt">${esc(q?.prompt || 'No question generated.')}</p>
      <p class="df-hint">Answer from memory. Do not open notes.</p>
      <form class="df-form" data-form="check">
        <label class="df-label">Your answer
          <textarea class="df-textarea df-textarea--lg" name="answer" rows="5" placeholder="Write your answer here…"></textarea>
        </label>
        <div class="df-actions">
          <button class="btn btn--ok" type="button" data-action="check-pass">Pass</button>
          <button class="btn btn--warn" type="button" data-action="check-partial">Partial</button>
          <button class="btn btn--fail" type="button" data-action="check-fail">Fail</button>
        </div>
      </form>
    </div>`;
}

// ─── Step 7: Reflection ───────────────────────────────────────────────────────

function renderReflect(state) {
  return `
    <div class="df-card">
      <h2 class="df-step-title">Reflection</h2>
      <p class="df-hint">3–5 minutes. Improve your calibration and make confusion reusable.</p>
      ${state.loading ? `<p class="df-loading">Saving…</p>` : ''}
      ${state.error ? `<p class="df-error-msg">${esc(state.error)}</p>` : ''}
      <form class="df-form" data-form="reflect">
        <label class="df-label">What felt clearer now?
          <textarea class="df-textarea" name="clearer" rows="2" placeholder="What clicked?"></textarea>
        </label>
        <label class="df-label">What still feels fuzzy?
          <textarea class="df-textarea" name="fuzzy" rows="2" placeholder="Where does understanding still collapse?"></textarea>
        </label>
        <label class="df-label">What connection felt most interesting?
          <textarea class="df-textarea" name="interesting_connection" rows="2" placeholder="Which link surprised you?"></textarea>
        </label>
        <label class="df-label">What would you want to test again later?
          <textarea class="df-textarea" name="test_later" rows="2" placeholder="Flag for next session…"></textarea>
        </label>
        <label class="df-label">Friction score (1 = smooth, 5 = struggled)
          <input class="df-input df-input--sm" name="friction_score" type="number" min="1" max="5" value="3" />
        </label>
        <div class="df-actions">
          <button class="btn btn--primary" type="submit">Save &amp; Continue →</button>
        </div>
      </form>
    </div>`;
}

// ─── Step 8: Review &amp; Scheduling ──────────────────────────────────────────

function renderSchedule(state) {
  const nodeList = state.nodesCreated.length
    ? state.nodesCreated.map(n => `<li>${esc(n.node_name)} — next review tomorrow</li>`).join('')
    : '<li class="df-empty-item">No nodes created this session</li>';

  const connList = state.connectionsCreated.length
    ? state.connectionsCreated.map(c => `<li>${esc(c.node_a)} → ${esc(c.node_b)}</li>`).join('')
    : '<li class="df-empty-item">No connections created</li>';

  const reviewPassed = state.reviewResults.filter(r => r.passed).length;
  const reviewFailed = state.reviewResults.filter(r => !r.passed).length;

  return `
    <div class="df-card">
      <h2 class="df-step-title">Review &amp; Scheduling</h2>
      <p class="df-hint">Review dates have been assigned. Confirm to close the session.</p>
      <div class="df-summary-grid">
        <div class="df-summary-cell">
          <span class="df-summary-num">${state.reviewResults.length}</span>
          <span class="df-summary-label">reviewed</span>
          <span class="df-summary-sub">${reviewPassed}✓ ${reviewFailed}✗</span>
        </div>
        <div class="df-summary-cell">
          <span class="df-summary-num">${state.nodesCreated.length}</span>
          <span class="df-summary-label">nodes</span>
        </div>
        <div class="df-summary-cell">
          <span class="df-summary-num">${state.connectionsCreated.length}</span>
          <span class="df-summary-label">connections</span>
        </div>
        <div class="df-summary-cell">
          <span class="df-summary-num">${state.checkResult ? (state.checkResult === 'pass' ? '✓' : '~') : '—'}</span>
          <span class="df-summary-label">check</span>
        </div>
      </div>
      <h3 class="df-sub-heading">Nodes scheduled</h3>
      <ul class="df-saved-list">${nodeList}</ul>
      <h3 class="df-sub-heading">Connections recorded</h3>
      <ul class="df-saved-list">${connList}</ul>
      <div class="df-actions">
        <button class="btn btn--primary" data-action="advance">Close Session →</button>
      </div>
    </div>`;
}

// ─── Step 9: Done / Summary ───────────────────────────────────────────────────

function renderDone(state, ctx) {
  const { date, sessionPath } = state;
  const vaultName = 'My_Data';
  const relPath = sessionPath
    ? sessionPath.replace(/\\/g, '/').replace(/.*11_Learning\//, '11_Learning/')
    : '';
  const obsidianLink = relPath
    ? `obsidian://open?vault=${encodeURIComponent(vaultName)}&file=${encodeURIComponent(relPath)}`
    : null;

  return `
    <div class="df-card">
      <h2 class="df-step-title">Session Complete — ${esc(date || '')}</h2>
      <p class="df-status df-status--ok">Well done. Small residue beats grand plans.</p>
      <div class="df-summary-grid">
        <div class="df-summary-cell">
          <span class="df-summary-num">${state.reviewResults.length}</span>
          <span class="df-summary-label">reviewed</span>
        </div>
        <div class="df-summary-cell">
          <span class="df-summary-num">${state.nodesCreated.length}</span>
          <span class="df-summary-label">nodes</span>
        </div>
        <div class="df-summary-cell">
          <span class="df-summary-num">${state.connectionsCreated.length}</span>
          <span class="df-summary-label">connections</span>
        </div>
      </div>
      ${obsidianLink ? `
        <div class="df-actions df-actions--mt">
          <a class="btn btn--secondary" href="${obsidianLink}">Open session note in Obsidian</a>
        </div>` : ''}
      <div class="df-actions">
        <button class="btn btn--ghost" data-action="go-observatory">Back to Observatory</button>
      </div>
    </div>`;
}

// ─── Event handlers ───────────────────────────────────────────────────────────

function attachHandlers(container, state, dispatch, ctx) {
  container.querySelectorAll('[data-action]').forEach(el => {
    el.addEventListener('click', e => handleAction(e.currentTarget.dataset.action, e.currentTarget, state, dispatch, ctx));
  });
  container.querySelectorAll('[data-form]').forEach(form => {
    form.addEventListener('submit', e => { e.preventDefault(); handleFormSubmit(form.dataset.form, form, state, dispatch, ctx); });
  });
  // Session mode radio buttons
  container.querySelectorAll('input[name="session_mode"]').forEach(radio => {
    radio.addEventListener('change', e => dispatch({ type: 'SET_MODE', mode: e.target.value }));
  });
}

function handleAction(action, el, state, dispatch, ctx) {
  switch (action) {
    case 'advance':          dispatch({ type: 'ADVANCE' }); break;
    case 'clear-error':      dispatch({ type: 'CLEAR_ERROR' }); break;
    case 'review-pass':      submitReview(el.dataset.topic, true, state, dispatch, ctx); break;
    case 'review-fail':      submitReview(el.dataset.topic, false, state, dispatch, ctx); break;
    case 'save-content': {
      const ta = document.getElementById('df-content-input');
      if (ta) dispatch({ type: 'SET_CONTENT', value: ta.value });
      dispatch({ type: 'ADVANCE' });
      break;
    }
    case 'save-example': {
      const ta = document.getElementById('df-example-input');
      if (ta) dispatch({ type: 'SET_EXAMPLE', value: ta.value });
      dispatch({ type: 'ADVANCE' });
      break;
    }
    case 'start-session': {
      const sel = document.getElementById('df-topic-select');
      const free = document.getElementById('df-topic-free');
      const topicId = (sel && sel.value) || (free && free.value.trim()) || null;
      if (topicId) {
        const found = state.reviewQueue.find(i => i.topic_id === topicId);
        dispatch({ type: 'SET_TOPIC', topic: found || { topic_id: topicId, domain: '', level: 0 } });
      }
      dispatch({ type: 'ADVANCE' });
      break;
    }
    case 'search-resources':
      searchResources(state, dispatch, ctx); break;
    case 'load-check':
      loadCheck(state, dispatch, ctx); break;
    case 'check-pass':    submitCheck('pass', state, dispatch, ctx); break;
    case 'check-partial': submitCheck('partial', state, dispatch, ctx); break;
    case 'check-fail':    submitCheck('fail', state, dispatch, ctx); break;
    case 'go-observatory': ctx.navigate('observatory'); break;
  }
}

async function submitReview(topicId, passed, state, dispatch, ctx) {
  try {
    await ctx.api.post('/api/learn/check/submit', { topic_id: topicId, passed, mode: 'recall', response_text: '' });
  } catch { /* non-fatal */ }
  dispatch({ type: 'REVIEW_RESULT', topic_id: topicId, passed });
}

async function searchResources(state, dispatch, ctx) {
  const q = state.sessionTopic?.topic_id || '';
  if (!q) return;
  dispatch({ type: 'LOADING' });
  try {
    const data = await ctx.api.get(`/api/learn/resources/queue?topic_id=${encodeURIComponent(q)}`);
    // Surface in content area if results exist
    const ta = document.getElementById('df-content-input');
    if (ta && data.items?.length) {
      const header = `=== Related Papers (${data.items.length}) ===\n\n`;
      const lines = data.items.map(p => `${p.title} — ${p.source} (${p.date_pulled})\n${p.abstract || ''}\n${p.url || ''}`).join('\n\n---\n\n');
      ta.value = ta.value ? ta.value + '\n\n' + header + lines : header + lines;
    }
    dispatch({ type: 'CLEAR_ERROR' });
  } catch {
    // Resource queue endpoint may not exist yet — non-fatal
    dispatch({ type: 'CLEAR_ERROR' });
  }
}

async function loadCheck(state, dispatch, ctx) {
  const topicId = state.sessionTopic?.topic_id;
  if (!topicId) return;
  dispatch({ type: 'LOADING' });
  try {
    const data = await ctx.api.get(`/api/learn/check/generate?topic_id=${encodeURIComponent(topicId)}&mode=recall`);
    dispatch({ type: 'CHECK_LOADED', question: { prompt: data.prompt, type: data.type } });
  } catch (err) {
    dispatch({ type: 'ERROR', error: `Check generation failed: ${err.message}` });
  }
}

async function submitCheck(result, state, dispatch, ctx) {
  const answerEl = document.querySelector('[data-form="check"] [name="answer"]');
  const answer = answerEl?.value || '';
  dispatch({ type: 'LOADING' });
  try {
    await ctx.api.post('/api/learn/check/submit', {
      topic_id: state.sessionTopic?.topic_id,
      mode: 'recall',
      result,
      response_text: answer,
    });
    dispatch({ type: 'CHECK_RESULT', result });
  } catch (err) {
    dispatch({ type: 'ERROR', error: err.message });
  }
}

async function handleFormSubmit(formType, form, state, dispatch, ctx) {
  const data = Object.fromEntries(new FormData(form).entries());

  if (formType === 'node') {
    if (!data.node_name || !data.primary_domain) return;
    dispatch({ type: 'LOADING' });
    try {
      const result = await ctx.api.post('/api/learn/node/create', { ...data, origin_session: state.date, confidence_rating: Number(data.confidence_rating) || 0 });
      dispatch({ type: 'NODE_CREATED', slug: result.slug, node_name: data.node_name });
      form.reset();
    } catch (err) { dispatch({ type: 'ERROR', error: err.message }); }
  }

  if (formType === 'connection') {
    if (!data.node_a || !data.node_b) return;
    dispatch({ type: 'LOADING' });
    try {
      const result = await ctx.api.post('/api/learn/connection/create', { ...data, origin_session: state.date });
      dispatch({ type: 'CONNECTION_CREATED', slug: result.slug, node_a: data.node_a, node_b: data.node_b });
      form.reset();
    } catch (err) { dispatch({ type: 'ERROR', error: err.message }); }
  }

  if (formType === 'reflect') {
    dispatch({ type: 'LOADING' });
    const reflection = [data.clearer, data.fuzzy, data.interesting_connection, data.test_later].filter(Boolean).join(' | ');
    try {
      await ctx.api.patch('/api/learn/session/log', {
        date: state.date,
        nodes_created: state.nodesCreated.length,
        connections_created: state.connectionsCreated.length,
        friction_score: Number(data.friction_score) || null,
        reflection,
      });
      dispatch({ type: 'LOG_SAVED' });
      dispatch({ type: 'ADVANCE' });
    } catch (err) { dispatch({ type: 'ERROR', error: err.message }); }
  }
}

// ─── Utility ──────────────────────────────────────────────────────────────────

function esc(str) {
  return String(str ?? '')
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

