/* ============================================================
   Button variants (BEM aliases used by daily-flow)
   ============================================================ */
.btn--primary  { background: var(--color-accent); color: #fff; }
.btn--secondary { background: var(--color-border); color: var(--color-text); }
.btn--ghost    { background: transparent; color: var(--color-muted); border: 1px solid var(--color-border); }
.btn--ok       { background: rgba(34, 197, 94, 0.15);  color: var(--color-success); border: 1px solid rgba(34, 197, 94, 0.3); }
.btn--fail     { background: rgba(239, 68, 68, 0.15);  color: var(--color-danger);  border: 1px solid rgba(239, 68, 68, 0.3); }
.btn--warn     { background: rgba(245,158, 11, 0.15);  color: var(--color-warning); border: 1px solid rgba(245,158, 11, 0.3); }
.btn--primary:hover, .btn--ok:hover, .btn--fail:hover { opacity: 0.85; }

/* ============================================================
   Daily Flow — layout shell
   ============================================================ */
.df-wrap {
  max-width: 680px;
  margin: 0 auto;
  padding: var(--space-lg) var(--space-md);
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
}

/* ============================================================
   Daily Flow — breadcrumb
   ============================================================ */
.df-breadcrumb {
  display: flex;
  align-items: center;
  gap: 6px;
  flex-wrap: wrap;
}

.df-crumb {
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  color: var(--color-muted);
