  letter-spacing: 0.05em;
}

.df-req { color: var(--color-danger); }

.df-input {
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text);
  font-size: 14px;
  padding: 9px 12px;
  outline: none;
  transition: border-color 0.15s;
  font-family: inherit;
}

.df-input:focus   { border-color: var(--color-accent); }
.df-input--sm     { max-width: 100px; }
.df-input--mt     { margin-top: var(--space-xs); }

.df-textarea {
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text);
  font-size: 14px;
  padding: 9px 12px;
  outline: none;
  resize: vertical;
  min-height: 72px;
  font-family: inherit;
  line-height: 1.5;
  transition: border-color 0.15s;
}

.df-textarea:focus   { border-color: var(--color-accent); }
.df-textarea--lg     { min-height: 120px; }

.df-select {
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text);
  font-size: 14px;
  padding: 9px 12px;
  outline: none;
  font-family: inherit;
  cursor: pointer;
}

.df-select:focus { border-color: var(--color-accent); }

/* ============================================================
   Daily Flow — actions row
   ============================================================ */
.df-actions {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-sm);
  padding-top: var(--space-sm);
}

.df-actions--mt { margin-top: var(--space-sm); }

/* ============================================================
   Daily Flow — saved list
   ============================================================ */
.df-saved-list {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.df-saved-list li {
  font-size: 13px;
  color: var(--color-text);
  padding: 4px var(--space-sm);
  background: rgba(34, 197, 94, 0.06);
  border-radius: var(--radius-sm);
}

/* ============================================================
   Daily Flow — summary grid
   ============================================================ */
.df-summary-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: var(--space-md);
}

.df-summary-cell {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
  padding: var(--space-md);
  background: var(--color-bg);
  border-radius: var(--radius-md);
  border: 1px solid var(--color-border);
}

.df-summary-num {
  font-size: 28px;
  font-weight: 700;
  color: var(--color-text);
  line-height: 1;
}

.df-summary-label {
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--color-muted);
}

.df-summary-sub {
  font-size: 11px;
  color: var(--color-muted);
}

