function renderStart(state) {
  if (!state.preflight) return `<div class="df-card"><p class="df-loading">Running checks…</p></div>`;

  // Preflight — show as a subtle collapsed indicator, not the focus
  const blocking = state.preflight.checks.slice(0, 3);
  const allOk = blocking.every(c => c.ok);
  const preflightBadge = allOk
    ? `<span class="df-badge" style="background:rgba(34,197,94,0.12);color:var(--color-success);">✓ System ready</span>`
    : `<span class="df-badge df-badge--warn">⚠ ${blocking.filter(c => !c.ok).length} check failed</span>`;

  // Due node cards — primary UI element
  const nodeCards = state.reviewQueue.length
    ? state.reviewQueue.slice(0, 6).map(item => {
        const overdueTxt = item.overdue_days > 0
          ? `<span class="df-node-overdue">${item.overdue_days}d overdue</span>`
          : `<span class="df-node-due-today">due today</span>`;
        return `
          <div class="df-node-card" data-action="pick-and-start"
               data-topic="${esc(item.topic_id)}" data-domain="${esc(item.domain || '')}" data-level="${item.level}">
            <div>
              <div class="df-node-card-name">${esc(item.topic_id)}</div>
              <div class="df-node-card-meta">${esc(item.domain || 'Unknown')} · Level ${item.level} · ${overdueTxt}</div>
            </div>
            <span class="df-arrow">→</span>
          </div>`;
      }).join('')
    : `<p class="df-empty">No items due — type a topic below to start fresh.</p>`;

  // Mode buttons
  const MODES = [
    { id: 'standard',     label: 'Standard' },
    { id: 'light',        label: 'Light' },
    { id: 'interweave',   label: 'Interweave' },
    { id: 'review-heavy', label: 'Review' },
  ];
  const modeBtns = MODES.map(m =>
    `<button class="df-mode-btn ${state.sessionMode === m.id ? 'df-mode-btn--active' : ''}"
       data-action="set-mode" data-mode="${m.id}">${m.label}</button>`
  ).join('');

  return `
    <div class="df-card">
      <div class="df-actions" style="justify-content:space-between;padding:0;">
        <h2 class="df-step-title">What are you learning today? ${preflightBadge}</h2>
      </div>

      <div class="df-picker-section">
        <span class="df-picker-label">Due for review — click to start</span>
        <div class="df-node-cards">${nodeCards}</div>
      </div>

      <div class="df-picker-section">
        <span class="df-picker-label">Or start a new topic</span>
        <div class="df-new-topic-row">
          <input class="df-input" id="df-topic-free" placeholder="Type a topic name…" />
          <button class="btn btn--primary" data-action="start-new-topic">Start →</button>
        </div>
      </div>

      <div class="df-mode-row">
        <span class="df-mode-row-label">Mode:</span>
        ${modeBtns}
      </div>
    </div>`;
}

