async function handleResourcesQueue(res, paths, topicId) {
  // Build keyword list from topic_id slug (e.g. "foundations-systems-thinking" → ["systems", "thinking"])
  const stopWords = new Set(['foundations', 'and', 'the', 'of', 'in', 'a', 'how', 'why', 'what']);
  const keywords = (topicId || '')
    .toLowerCase()
    .split(/[-\s]+/)
    .filter(w => w.length > 2 && !stopWords.has(w));

  if (!keywords.length) return sendJson(res, { items: [], count: 0 });

  // Scan research pull notes and 09_Resources for matches
  const researchRoot = join(getLearningRoot(), '..', '05_Data_Pulls', 'Research');
  const resourcesRoot = paths.resources;
  const items = [];

  async function scanDir(dir) {
    let files;
    try { files = await readdir(dir, { withFileTypes: true }); } catch { return; }
    for (const f of files) {
      if (!f.isFile() || extname(f.name) !== '.md' || f.name.startsWith('_')) continue;
      const filePath = join(dir, f.name);
      try {
        const raw = await readFile(filePath, 'utf8');
        const lower = raw.toLowerCase();
        // Include note if any keyword appears in the content
        if (!keywords.some(k => lower.includes(k))) continue;

        const { data, content } = parseRawNote(raw);
        // Extract first URL from content (handles both arXiv and DOI links)
        const urlMatch = content.match(/\[(?:arXiv|DOI|PMID[:\s]*\d+|Link)\]\((https?[^\)]+)\)/i)
          || content.match(/(https?:\/\/[^\s\)\"]+)/);
        const url = urlMatch ? urlMatch[1] : '';

        // Extract a brief abstract-like excerpt (first non-table, non-header line)
        const excerpt = content.split('\n')
          .find(l => l.trim() && !l.startsWith('#') && !l.startsWith('|') && !l.startsWith('-') && l.length > 40)
          ?.trim() || '';

        items.push({
          title:      data.title || f.name.replace(/\.md$/, ''),
          source:     data.source || 'Vault',
          date_pulled: data.date_pulled || '',
          abstract:   excerpt.slice(0, 300),
          url,
        });
      } catch { /* skip */ }
    }
  }

  await scanDir(researchRoot);
  await scanDir(resourcesRoot);

  // Most recent first
  items.sort((a, b) => (b.date_pulled || '').localeCompare(a.date_pulled || ''));
  sendJson(res, { items: items.slice(0, 8), count: items.length });
}

