async function searchResources(state, dispatch, ctx) {
  const topicId = state.sessionTopic?.topic_id || '';
  if (!topicId) return;
  dispatch({ type: 'LOADING' });
  try {
    const data = await ctx.api.get(`/api/learn/resources/queue?topic_id=${encodeURIComponent(topicId)}`);
    const ta = document.getElementById('df-content-input');
    if (ta) {
      if (data.items?.length) {
        const header = `=== Related Papers (${data.items.length}) ===\n\n`;
        const lines = data.items.map(p =>
          [p.title, `Source: ${p.source}${p.date_pulled ? ' · ' + p.date_pulled : ''}`, p.abstract, p.url]
            .filter(Boolean).join('\n')
        ).join('\n\n---\n\n');
        ta.value = ta.value ? `${ta.value}\n\n${header}${lines}` : `${header}${lines}`;
      } else {
        // Show feedback inline rather than silently doing nothing
        ta.placeholder = `No papers found for "${topicId.replace(/-/g, ' ')}" in your research pulls. Paste content manually or pull new papers first.`;
      }
    }
    dispatch({ type: 'CLEAR_ERROR' });
  } catch (err) {
    dispatch({ type: 'ERROR', error: `Paper search failed: ${err.message}` });
  }
}

